  ('pukao-0a2fc18c-moex-00132', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '給定貢丸的市場需求函數Q =22–3P+0.2P，其中Q 為貢丸的需求量，P為貢丸的市場價格，P為魚丸的 D F D F 市場價格。根據這些資訊，下列敘述何者正確？', '["貢丸屬於豬肉製品，魚丸屬於魚肉製品，此需求曲線印證了此二產品彼此需求並不相關", "若是魚丸的價格上升1個百分點，貢丸的需求量會上升0.2個百分點", "對消費者而言，貢丸和魚丸是互補品", "貢丸的需求滿足「需求法則」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00133', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '在完全競爭市場中，當廠商生產產品的數量等於市場均衡數量時，下列敘述何者錯誤？', '["生產最後一個單位產品的邊際收益等於邊際成本", "消費者的剩餘和生產者的剩餘被極大化", "資源被有效的運用在生產過程中", "廠商繼續生產下一單位產品仍可獲利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00134', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '魯濱遜在荒島上，他每小時可摘10個椰子或抓1條魚。他的朋友每小時可摘30個椰子或抓2條魚。下列敘述 何者正確？', '["以抓魚而言，魯濱遜具有絕對利益", "以抓魚而言，魯濱遜具有比較利益", "以摘椰子而言，魯濱遜具有絕對利益", "以摘椰子而言，魯濱遜具有比較利益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00135', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '張三的所得剛好消費甲商品2單位與乙商品10單位；或是剛好消費甲商品4單位與乙商品2單位。若張三將 其所得全部消費於乙商品，則可購買多少單位的乙商品？', '["12單位", "14單位", "16單位", "18單位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00136', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '營建業工人的工資上升將導致新房屋市場的：', '["需求曲線整條向右移動", "需求曲線整條向左移動", "供給曲線整條向右移動", "供給曲線整條向左移動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00137', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '已知每杯珍奶的價格為30元。對於購買的第一杯珍奶，小明願意支付50元，第二杯40元，第三杯30元，第 四杯20元。則小明購買珍奶的消費者總剩餘為多少元？', '["20", "90", "30", "100"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00138', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '關於無異曲線（Indifferencecurve）的說明，下列何種情形不會出現？', '["消費增加則效用增加", "相交的無異曲線", "無異曲線為負斜率", "消費者不會有最大滿足點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
